COMMENT ON COLUMN smon_analysis_runs.error_message IS 'Error details if status=failed';

-- AI model settings table
-- Stores configurable model IDs for diagnosis and remediation pipelines.
-- Both use OpenRouter (OPENROUTER_API_KEY).

create table if not exists smon_ai_settings (
  id uuid primary key default gen_random_uuid(),
  key text not null unique,
  value text not null,
  updated_at timestamptz not null default now()
);

alter table smon_ai_settings enable row level security;

create policy "authenticated_read" on smon_ai_settings
  for select to authenticated using (true);

create policy "authenticated_write" on smon_ai_settings
  for all to authenticated using (true) with check (true);

-- Defaults: diagnosis uses Gemini 2.5 Flash (bulk log analysis, cheap + fast),
-- remediation uses GPT-5.4 (NAS Copilot, needs stronger reasoning for SSH fix commands).
insert into smon_ai_settings (key, value) values
  ('diagnosis_model',   'google/gemini-2.5-flash'),
  ('remediation_model', 'openai/gpt-5.4')
on conflict (key) do nothing;

-- Service health tracking: the agent monitors key DSM services
CREATE TABLE IF NOT EXISTS smon_service_health (
  id           uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  nas_id       text NOT NULL,
  service_name text NOT NULL,
  status       text NOT NULL, -- running, stopped, not_found
  captured_at  timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_smon_service_health_recent
  ON smon_service_health (nas_id, captured_at DESC);

ALTER TABLE smon_service_health ENABLE ROW LEVEL SECURITY;
CREATE POLICY "authenticated users manage service health"
  ON smon_service_health FOR ALL TO authenticated
  USING (true) WITH CHECK (true);

-- Track how often each custom metric is referenced in analysis
-- When referenced_count >= 3, the metric is consistently useful
-- and should be promoted to a built-in agent collector.
ALTER TABLE smon_custom_metric_schedules
  ADD COLUMN IF NOT EXISTS referenced_count int NOT NULL DEFAULT 0;

create table smon_resolution_messages (
  id uuid primary key default gen_random_uuid(),
  resolution_id uuid references smon_issue_resolutions(id) on delete cascade not null,
  user_id uuid not null,
  role text not null check (role in ('user', 'agent')),
  content text not null,
  created_at timestamptz default now() not null
);
create index on smon_resolution_messages(resolution_id, created_at);

alter table smon_resolution_messages enable row level security;

create policy "authenticated_all" on smon_resolution_messages
  for all
  to authenticated
  using (true)
  with check (true);

create unique index if not exists smon_issues_user_fingerprint_unique
on public.smon_issues (user_id, fingerprint)
where fingerprint is not null;

-- Rebuild foundation schema.
-- Adds capability state, ingestion health/events, normalized facts, issue job queue,
-- and explicit issue state transition history.

create table if not exists smon_capability_state (
  id uuid primary key default gen_random_uuid(),
  nas_id uuid not null references smon_nas_units(id) on delete cascade,
  capability_key text not null,
  state text not null check (state in ('supported', 'unsupported', 'unverified', 'degraded')),
  source_kind text not null default 'collector',
  evidence text not null default '',
  raw_error text,
  metadata jsonb not null default '{}'::jsonb,
  checked_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (nas_id, capability_key)
);

create index if not exists idx_smon_capability_state_nas_checked
  on smon_capability_state (nas_id, checked_at desc);

create table if not exists smon_ingestion_health (
  id uuid primary key default gen_random_uuid(),
  nas_id uuid references smon_nas_units(id) on delete cascade,
  component_key text not null,
  state text not null check (state in ('healthy', 'degraded', 'failed', 'unknown')),
  summary text not null default '',
  metadata jsonb not null default '{}'::jsonb,
  updated_at timestamptz not null default now(),
