139	CREATE OR REPLACE FUNCTION smon_run_anomaly_detection()
140	RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$
141	DECLARE
142	  api_key text;
143	  metrics_summary jsonb;
144	  nas record;
145	  prompt_text text;
146	  has_anomaly boolean := false;
147	BEGIN
148	  api_key := smon_get_openai_key();
149	  IF api_key IS NULL THEN RETURN; END IF;
150	
151	  FOR nas IN SELECT id, name FROM nas_units WHERE status != 'offline' LOOP
152	    SELECT jsonb_agg(jsonb_build_object(
153	      'metric', type, 'avg', round(avg_val::numeric,2), 'max', round(max_val::numeric,2),
154	      'min', round(min_val::numeric,2), 'stddev', round(coalesce(stddev_val,0)::numeric,2),
155	      'current', round(latest_val::numeric,2), 'unit', unit
156	    ))
157	    INTO metrics_summary
158	    FROM (
159	      SELECT type, unit, avg(value) AS avg_val, max(value) AS max_val, min(value) AS min_val,
160	             stddev(value) AS stddev_val, (array_agg(value ORDER BY recorded_at DESC))[1] AS latest_val
161	      FROM metrics WHERE nas_id = nas.id AND recorded_at > now() - interval '1 hour'
162	      GROUP BY type, unit
163	    ) agg;
164	
165	    IF metrics_summary IS NULL THEN CONTINUE; END IF;
166	
167	    SELECT exists(
168	      SELECT 1 FROM jsonb_array_elements(metrics_summary) elem
169	      WHERE (elem->>'stddev')::float > 0
170	        AND abs((elem->>'current')::float - (elem->>'avg')::float) > 1.5*(elem->>'stddev')::float
171	    ) INTO has_anomaly;
172	
173	    IF NOT has_anomaly THEN CONTINUE; END IF;
174	
175	    prompt_text := format(
176	      'You are a NAS monitoring AI. Analyze these metrics from NAS "%s" and identify anomalies. '
177	      'Respond in JSON: {"anomalies":[{"severity":"...","category":"...","description":"...","recommendation":"..."}],"summary":"..."}'
178	      E'\n\nMetrics:\n%s', nas.name, metrics_summary::text
179	    );
180	
181	    PERFORM net.http_post(
182	      url := 'https://api.openai.com/v1/chat/completions',
183	      headers := jsonb_build_object('Content-Type','application/json','Authorization','Bearer '||api_key),
184	      body := jsonb_build_object(
185	        'model','gpt-5.4-mini','max_tokens',1000,
186	        'response_format',jsonb_build_object('type','json_object'),
187	        'messages',jsonb_build_array(
188	          jsonb_build_object('role','system','content','You are a NAS infrastructure monitoring AI. Respond only in valid JSON.'),
189	          jsonb_build_object('role','user','content',prompt_text)
190	        )
191	      )
192	    );
193	  END LOOP;
194	END;
195	$$;
