197	CREATE OR REPLACE FUNCTION smon_run_daily_health()
198	RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$
199	DECLARE
200	  api_key text;
201	  report_data jsonb;
202	  prompt_text text;
203	BEGIN
204	  api_key := smon_get_openai_key();
205	  IF api_key IS NULL THEN RETURN; END IF;
