207	  SELECT jsonb_build_object(
208	    'nas_units', (SELECT jsonb_agg(jsonb_build_object('name',name,'status',status,'last_seen',last_seen)) FROM nas_units),
209	    'metrics_24h', (
210	      SELECT jsonb_agg(jsonb_build_object(
211	        'nas_name',n.name,'metric',m.type,
212	        'avg',round(avg(m.value)::numeric,2),'max',round(max(m.value)::numeric,2),'min',round(min(m.value)::numeric,2)
213	      ))
214	      FROM metrics m JOIN nas_units n ON m.nas_id = n.id
215	      WHERE m.recorded_at > now() - interval '24 hours' GROUP BY n.name, m.type
216	    ),
217	    'storage', (
218	      SELECT jsonb_agg(distinct_on_vol) FROM (
219	        SELECT DISTINCT ON (nas_id, volume_id)
220	          jsonb_build_object('nas_name',n.name,'volume',s.volume_path,
221	            'used_pct',round((s.used_bytes::numeric/nullif(s.total_bytes,0)*100),1),
222	            'status',s.status,'raid_type',s.raid_type) AS distinct_on_vol
223	        FROM storage_snapshots s JOIN nas_units n ON s.nas_id = n.id
224	        ORDER BY nas_id, volume_id, recorded_at DESC
225	      ) latest
226	    ),
227	    'active_alerts', (SELECT count(*) FROM alerts WHERE status = 'active'),
228	    'security_events_24h', (SELECT count(*) FROM security_events WHERE detected_at > now() - interval '24 hours'),
229	    'recent_security', (
230	      SELECT jsonb_agg(jsonb_build_object('type',type,'severity',severity,'title',title))
231	      FROM (SELECT type,severity,title FROM security_events WHERE detected_at > now() - interval '24 hours' ORDER BY detected_at DESC LIMIT 10) r
232	    )
233	  ) INTO report_data;
234	
235	  prompt_text := format(
236	    'Generate a daily health report for my Synology NAS infrastructure. '
237	    'Respond in JSON: {"overall_status":"healthy|warning|critical","summary":"...","findings":[{"severity":"...","category":"...","description":"..."}],"recommendations":["..."],"storage_predictions":[{"volume":"...","days_until_full":0,"recommendation":"..."}]}'
238	    E'\n\nData:\n%s', report_data::text
239	  );
240	
241	  PERFORM net.http_post(
242	    url := 'https://api.openai.com/v1/chat/completions',
243	    headers := jsonb_build_object('Content-Type','application/json','Authorization','Bearer '||api_key),
244	    body := jsonb_build_object(
245	      'model','gpt-5.4-mini','max_tokens',1500,
246	      'response_format',jsonb_build_object('type','json_object'),
247	      'messages',jsonb_build_array(
248	        jsonb_build_object('role','system','content','You are a NAS infrastructure monitoring AI. Respond only in valid JSON.'),
249	        jsonb_build_object('role','user','content',prompt_text)
250	      )
251	    )
252	  );
253	END;
254	$$;
