256	CREATE OR REPLACE FUNCTION smon_process_ai_responses()
257	RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$
258	DECLARE
259	  resp record; body jsonb; choices jsonb; content jsonb;
260	  analysis_type text; finding jsonb;
261	BEGIN
262	  FOR resp IN
263	    SELECT id, status_code, body::jsonb AS response_body FROM net._http_response
264	    WHERE status_code IS NOT NULL AND body::text LIKE '%"choices"%'
265	      AND id NOT IN (SELECT (details->>'pg_net_id')::bigint FROM ai_analyses WHERE details ? 'pg_net_id')
266	    ORDER BY created DESC LIMIT 10
267	  LOOP
268	    BEGIN
269	      body := resp.response_body; choices := body->'choices';
270	      IF choices IS NULL OR jsonb_array_length(choices) = 0 THEN CONTINUE; END IF;
271	      content := (choices->0->'message'->>'content')::jsonb;
272	      analysis_type := CASE
273	        WHEN content ? 'anomalies' THEN 'anomaly_detection'
274	        WHEN content ? 'overall_status' THEN 'daily_health'
275	        WHEN content ? 'security_findings' THEN 'security_review'
276	        WHEN content ? 'storage_predictions' THEN 'storage_prediction'
277	        ELSE 'anomaly_detection' END;
278	
279	      INSERT INTO ai_analyses (type, summary, findings, recommendations, model, tokens_used, details)
280	      VALUES (
281	        analysis_type,
282	        coalesce(content->>'summary', content->>'overall_status', 'Analysis complete'),
283	        coalesce(content->'findings', content->'anomalies', '[]'::jsonb),
284	        coalesce(content->'recommendations', '[]'::jsonb),
285	        'gpt-5.4-mini', coalesce((body->'usage'->>'total_tokens')::int, 0),
286	        jsonb_build_object('pg_net_id', resp.id)
287	      );
288	
289	      FOR finding IN SELECT * FROM jsonb_array_elements(coalesce(content->'findings', content->'anomalies', '[]'::jsonb)) LOOP
290	        IF finding->>'severity' IN ('warning','critical') THEN
291	          PERFORM smon_create_alert(null, finding->>'severity',
292	            format('AI: %s', coalesce(finding->>'category', finding->>'description')),
293	            coalesce(finding->>'description',''), finding);
294	        END IF;
295	      END LOOP;
296	    EXCEPTION WHEN others THEN CONTINUE;
297	    END;
298	  END LOOP;
299	END;
300	$$;
