302	CREATE OR REPLACE FUNCTION smon_detect_sync_anomalies()
303	RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$
304	DECLARE
305	  conflict_count int; empty_folder_count int; sync_error_count int; rapid_delete_count int; nas record;
306	BEGIN
307	  FOR nas IN SELECT id, name FROM nas_units WHERE status != 'offline' LOOP
308	    SELECT count(*) INTO conflict_count FROM nas_logs
309	    WHERE nas_id=nas.id AND source IN ('drive','drive_sharesync')
310	      AND message ILIKE '%conflict%' AND ingested_at > now()-interval '1 hour';
311	
312	    SELECT count(*) INTO empty_folder_count FROM nas_logs
313	    WHERE nas_id=nas.id AND source IN ('drive','drive_sharesync')
314	      AND (message ILIKE '%mkdir%' OR message ILIKE '%create%folder%')
315	      AND message NOT ILIKE '%file%' AND ingested_at > now()-interval '1 hour';
316	
317	    SELECT count(*) INTO sync_error_count FROM nas_logs
318	    WHERE nas_id=nas.id AND source IN ('drive','drive_sharesync','drive_server')
319	      AND severity IN ('error','critical') AND ingested_at > now()-interval '1 hour';
320	
321	    SELECT count(*) INTO rapid_delete_count FROM nas_logs
322	    WHERE nas_id=nas.id AND source IN ('drive','drive_sharesync')
323	      AND (message ILIKE '%delete%' OR message ILIKE '%remove%')
324	      AND ingested_at > now()-interval '5 minutes';
325	
326	    IF conflict_count > 3 THEN
327	      INSERT INTO alerts (nas_id,severity,status,source,title,message,details) VALUES
328	        (nas.id,'warning','active','ai','High Sync Conflict Rate Detected',
329	         format('%s sync conflicts in last hour on %s.',conflict_count,nas.name),
330	         jsonb_build_object('conflict_count',conflict_count,'time_window','1 hour'));
331	    END IF;
332	    IF sync_error_count > 0 THEN
333	      INSERT INTO alerts (nas_id,severity,status,source,title,message,details) VALUES
334	        (nas.id,'error','active','ai','Sync Errors Detected',
335	         format('%s sync errors in last hour on %s.',sync_error_count,nas.name),
336	         jsonb_build_object('error_count',sync_error_count,'time_window','1 hour'));
337	    END IF;
338	    IF rapid_delete_count > 5 THEN
339	      INSERT INTO alerts (nas_id,severity,status,source,title,message,details) VALUES
340	        (nas.id,'warning','active','ai','Rapid Delete Activity',
341	         format('%s deletes in 5 min on %s.',rapid_delete_count,nas.name),
342	         jsonb_build_object('delete_count',rapid_delete_count,'time_window','5 minutes'));
343	    END IF;
344	  END LOOP;
345	END;
346	$$;
