392	CREATE OR REPLACE FUNCTION smon_detect_stuck_syncs()
393	RETURNS TABLE (nas_id UUID, nas_name TEXT, task_info TEXT, file_path TEXT, task_id TEXT)
394	LANGUAGE plpgsql SECURITY DEFINER AS $$
395	DECLARE stuck_log RECORD;
396	BEGIN
397	  FOR stuck_log IN
398	    SELECT sl.nas_id, nas.name, sl.message, sl.logged_at
399	    FROM nas_logs sl JOIN nas_units nas ON sl.nas_id = nas.id
400	    WHERE sl.source IN ('drive_sharesync','drive_server')
401	      AND sl.message ILIKE '%syncing%' AND sl.message NOT ILIKE '%done%'
402	      AND sl.message NOT ILIKE '%complete%' AND sl.message NOT ILIKE '%error%'
403	      AND sl.ingested_at > now()-interval '30 minutes'
404	    ORDER BY sl.ingested_at DESC
405	  LOOP
406	    nas_id := stuck_log.nas_id; nas_name := stuck_log.name;
407	    task_info := stuck_log.message; file_path := null; task_id := null;
408	    RETURN NEXT;
409	  END LOOP;
410	END;
411	$$;
