413	CREATE OR REPLACE FUNCTION smon_detect_sync_conflicts()
414	RETURNS TABLE (nas_id UUID, nas_name TEXT, file_path TEXT, conflict_type TEXT, both_sides JSONB)
415	LANGUAGE plpgsql SECURITY DEFINER AS $$
416	DECLARE conflict_log RECORD;
417	BEGIN
418	  FOR conflict_log IN
419	    SELECT sl.nas_id, nas.name, sl.message, sl.metadata
420	    FROM nas_logs sl JOIN nas_units nas ON sl.nas_id = nas.id
421	    WHERE sl.source IN ('drive_sharesync')
422	      AND (sl.message ILIKE '%conflict%' OR sl.message ILIKE '%both modified%'
423	        OR sl.message ILIKE '%version conflict%' OR sl.message ILIKE '%already exists%')
424	      AND sl.ingested_at > now()-interval '1 hour'
425	    ORDER BY sl.ingested_at DESC
426	  LOOP
427	    nas_id := conflict_log.nas_id; nas_name := conflict_log.name;
428	    file_path := conflict_log.metadata->>'path';
429	    conflict_type := CASE WHEN conflict_log.message ILIKE '%conflict%' THEN 'file_conflict'
430	                          WHEN conflict_log.message ILIKE '%already exists%' THEN 'duplicate_exists'
431	                          ELSE 'version_conflict' END;
432	    both_sides := conflict_log.metadata;
433	    RETURN NEXT;
434	  END LOOP;
435	END;
436	$$;
