480	CREATE OR REPLACE FUNCTION smon_run_sync_remediation()
481	RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$
482	DECLARE
483	  stuck RECORD; conflict RECORD; invalid RECORD; lock_issue RECORD;
484	  remediated_count INT := 0;
485	BEGIN
486	  FOR stuck IN SELECT * FROM smon_detect_stuck_syncs() LOOP
487	    IF NOT EXISTS (SELECT 1 FROM sync_remediations WHERE nas_id=stuck.nas_id AND file_path=stuck.file_path
488	        AND created_at > now()-interval '1 hour' AND status IN ('pending','in_progress')) THEN
489	      INSERT INTO sync_remediations (nas_id,task_id,file_path,issue_type,action_taken,details,status)
490	      VALUES (stuck.nas_id,stuck.task_id,stuck.file_path,'stuck_sync','flagged_for_review',
491	        jsonb_build_object('task_info',stuck.task_info,'detected_at',now()),'pending');
492	      remediated_count := remediated_count + 1;
493	    END IF;
494	  END LOOP;
495	
496	  FOR conflict IN SELECT * FROM smon_detect_sync_conflicts() LOOP
497	    IF conflict.file_path IS NOT NULL AND conflict.file_path != '' THEN
498	      INSERT INTO sync_remediations (nas_id,file_path,issue_type,original_name,action_taken,details,status)
499	      VALUES (conflict.nas_id,conflict.file_path,'conflict',conflict.file_path,'renamed_to_old',
500	        jsonb_build_object('conflict_type',conflict.conflict_type,'detected_at',now()),'pending');
501	      remediated_count := remediated_count + 1;
502	    END IF;
503	  END LOOP;
504	
505	  FOR invalid IN SELECT * FROM smon_detect_invalid_chars() LOOP
506	    INSERT INTO sync_remediations (nas_id,file_path,issue_type,action_taken,details,status)
507	    VALUES (invalid.nas_id,invalid.file_path,'invalid_chars','flagged_for_review',
508	      jsonb_build_object('invalid_chars_found',invalid.invalid_chars,'detected_at',now()),'pending');
509	    remediated_count := remediated_count + 1;
510	  END LOOP;
511	
512	  FOR lock_issue IN SELECT * FROM smon_detect_lock_timeouts() LOOP
513	    INSERT INTO sync_remediations (nas_id,file_path,issue_type,action_taken,details,status)
514	    VALUES (lock_issue.nas_id,lock_issue.file_path,'lock_timeout','cleared_lock',
515	      jsonb_build_object('detected_at',now()),'completed');
516	    remediated_count := remediated_count + 1;
517	  END LOOP;
518	
519	  IF remediated_count > 0 THEN
520	    INSERT INTO alerts (nas_id,severity,status,source,title,message,details) VALUES
521	      (null,'warning','active','ai','ShareSync Issues Detected - Review Required',
522	       format('%s ShareSync issues detected and logged.',remediated_count),
523	       jsonb_build_object('issue_count',remediated_count,'checked_at',now()));
524	  END IF;
525	END;
526	$$;
527	
528	CREATE OR REPLACE FUNCTION increment_metric_references(schedule_ids uuid[])
529	RETURNS void LANGUAGE sql AS $$
530	  UPDATE custom_metric_schedules SET referenced_count = referenced_count + 1 WHERE id = ANY(schedule_ids);
531	$$;
532	
533	
534	-- ============================================================
535	-- Update pg_cron job names and function references
536	-- ============================================================
537	
538	-- Remove old cron jobs (safe if pg_cron is installed; silently skips if not)
539	DO $outer$
540	BEGIN
541	  IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_cron') THEN
542	    DELETE FROM cron.job WHERE jobname IN (
543	      'smon-partition-maintenance',
544	      'smon-anomaly-detection',
545	      'smon-daily-health',
546	      'smon-process-ai-responses',
547	      'smon-sync-anomaly-detection',
548	      'smon-sync-health-analysis',
549	      'smon-weekly-sync-report',
550	      'smon-sync-remediation'
551	    );
552	
553	    -- Re-register with clean names
554	    PERFORM cron.schedule('partition-maintenance',  '0 7 * * *',   'SELECT public.run_maintenance_proc()');
555	    PERFORM cron.schedule('anomaly-detection',      '*/15 * * * *', 'SELECT smon_run_anomaly_detection()');
556	    PERFORM cron.schedule('daily-health',           '0 12 * * *',  'SELECT smon_run_daily_health()');
557	    PERFORM cron.schedule('process-ai-responses',   '* * * * *',   'SELECT smon_process_ai_responses()');
558	    PERFORM cron.schedule('sync-anomaly-detection', '*/15 * * * *', 'SELECT smon_detect_sync_anomalies()');
559	    PERFORM cron.schedule('sync-health-analysis',   '0 */4 * * *', 'SELECT smon_analyze_sync_health()');
560	    PERFORM cron.schedule('weekly-sync-report',     '0 8 * * 0',   'SELECT smon_generate_weekly_sync_report()');
561	    PERFORM cron.schedule('sync-remediation',       '*/15 * * * *', 'SELECT smon_run_sync_remediation()');
562	  END IF;
563	END;
564	$outer$;
